int trocas = 0;

// Função para "heapificar" um sub-heap de tamanho n
void heapify (int n, int i) 
{
    int maior = i;
    int filho_esquerdo = 2*i + 1;
    int filho_direito = 2*i + 2;
    
    // verifica se o filho esquerdo é maior que a raiz
    if(filho_esquerdo < n && entrada[filho_esquerdo] > entrada[maior] )
        maior = filho_esquerdo;

    // verifica se o filho direito é maior que o maior até agora
    if(filho_direito < n && entrada[filho_direito] > entrada[maior])
        maior = filho_direito;

    // se o maior não é a raiz, troca e continuar a heapificar
    if(maior != i)
    {
        // raiz desce
        int aux = entrada[i];
        entrada[i] = entrada[maior];
        entrada[maior] = aux;
        trocas++;

        // verifica se está no lugar certo (continua a heapificar)
        heapify(n, maior); 
    }
}


int main()
{
    
    // Exibir entrada e tamanho
    cout<<"Tamanho da lista : "<<tamanho<<endl;
    cout<<"Ordem de entrada : ";
    for(int i = 0; i < tamanho; i++)
    {
        cout<<entrada[i]<<", ";
    }
    
    // Construir o heap máximo
    for(int i = tamanho/2 - 1; i >= 0; i--) // percorre todos nós que possuem filhos
    {
        heapify(tamanho, i); 
    }
  
    // Extrair elemento do heap
    for(int i = tamanho-1; i > 0; i--)
    {
        // Move a raiz (maior elemento) pro final
        int aux = entrada[0];
        entrada[0] = entrada[i];
        entrada[i] = aux;
        trocas++;

        // Refaz o heap para o tamanho reduzido
        heapify(i, 0); 
    }


    // Exibir lista ordenada e quantia de trocas
    cout<<"\nOrdem de saida : ";
    for(int i = 0; i < tamanho; i++)
    {
        cout<<entrada[i]<<", ";
    }
    cout<<"\nTrocas : "<<trocas;

}